setup:
mkdir -p /tmp/eval_race && printf 'import threading, time

class Counter:
    def __init__(self):
        self.value = 0

    def increment(self):
        # BUG: the read-modify-write below is not atomic. The value is read
        # into a temporary, the thread yields, then the temporary + 1 is
        # written back — so concurrent increments interleave and lose updates.
        v = self.value
        time.sleep(0)
        self.value = v + 1


def run(counter, n):
    for _ in range(n):
        counter.increment()
' > /tmp/eval_race/counter.py
